VALUES
  ('real-estate-moex-00644', 'real-estate', 'real-estate-moex-108-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '依不動產估價技術規則之規定，運用計量模型分析法進行估價，下列敘述何者錯誤？', '["須蒐集應用計量模型分析關係式自變數個數五倍以上之比較標的", "本法須先求出各主要影響價格因素與比較標的價格二者之關係式，以推算各主要影響價格因素 之調整率及調整額之方法", "採迴歸分析者，其調整後判定係數不得低於零點八", "截距項以外其他各主要影響價格因素之係數估計值同時為零之顯著機率不得大於百分之五"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "39046373c53f", "answer_pdf_sha1": "e90f4c10ccf7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00645', 'real-estate', 'real-estate-moex-108-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '下列何者非屬不動產估價師受理委託估價之勘估標的？', '["土地及其權利估價", "建築改良物及其權利估價", "不動產租金估計", "不動產稅負之估算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "39046373c53f", "answer_pdf_sha1": "e90f4c10ccf7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00646', 'real-estate', 'real-estate-moex-108-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '不動產估價師在收集比較標的相關交易等案例及資料時，得向當事人、四鄰、其他不動產估價師、 不動產經紀人員、地政士、地政機關、金融機構、公地管理機關、司法機關、媒體或有關單位收 集之。請問：到實價登錄系統查詢交易案例相關資訊，屬向何者收集資料？', '["不動產經紀人", "地政士", "地政機關", "媒體"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "39046373c53f", "answer_pdf_sha1": "e90f4c10ccf7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00647', 'real-estate', 'real-estate-moex-108-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '對具有市場性之不動產，以違反經濟合理性之不動產分割為前提，查估其所形成之價值，並以貨 幣金額表示者，屬下列那一種價格？', '["特殊價格", "特定價格", "正常價格", "限定價格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "39046373c53f", "answer_pdf_sha1": "e90f4c10ccf7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00648', 'real-estate', 'real-estate-moex-108-ce711c8d', 'sub-real-estate-01', NULL, 'single_choice', '下列敘述何者為正確？', '["具有市場性之不動產，以不動產所有權以外其他權利與所有權合併為目的，查估其所形成之價 值，並以貨幣金額表示者，屬「限定價格」", "具有市場性之不動產，基於特定條件下形成之價值，並以貨幣金額表示者，為「特殊價格」", "對不具市場性之不動產所估計之價值，並以貨幣金額表示者，為「特定價格」", "對不具市場性之不動產，以不動產合併為目的，查估其所形成之價值，並以貨幣金額表示者， 屬「限定價格」"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "39046373c53f", "answer_pdf_sha1": "e90f4c10ccf7", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產估價概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00649', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'essay', '消費者保護法所規範之「企業經營者」之定義為何？而企業經營者從事
不動產交易應負該法第 7 條所規定之商品及服務責任，請詳述該條所規
定之商品或服務責任之構成要件及損害賠償為何？若消費者依商品或
服務責任提出訴訟時，得請求該法第 51 條懲罰性賠償金，請詳述該規
定為何？另詳述依該法第10 條，於何情形下，企業經營者有回收義務？
（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00650', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'essay', '不動產之買賣，如委由經紀業仲介者，不動產經紀業者應提出不動產經
紀業管理條例第 22 條第 1 項所規定之各類文件，其中包括不動產說明
書，而該條例第 22 條第 3 項對經紀業者所製作之不動產說明書內容有
何限制規定？另不動產說明書應有那些相關人等之簽章以及簽章之時
間點？在執行業務過程中，不動產說明書應如何解說？何者為義務人且
其解說的對象為何人？當買賣雙方當事人簽訂買賣契約書時，說明書應
如何處置，該不動產說明書則視為買賣契約書之一部分？若就不動產說
明書之製作及執行過程，有經紀人員因未盡其義務，致交易當事人受損
害者，則受損害者可請求何人負賠償責任？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00651', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '關於不動產經紀業營業保證金之敘述，以下何者錯誤？', '["營業保證金除不動產經紀業管理條例另有規定外，不因經紀業或經紀人員之債務債權關係而為 讓與、扣押或設定負擔", "不動產經紀業申請解散者，得自核准註銷營業之日滿一年後二年內，請求退還原繳存之營業保 證金。但不包括營業保證金之孳息", "應繳之營業保證金及繳存或提供擔保之辦法，由中華民國不動產仲介經紀業或代銷經紀業同業 公會全國聯合會定之", "經紀業因合併、變更組織時對其所繳存之營業保證金之權利應隨之移轉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00652', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依不動產經紀業管理條例規定，經紀業應依中央主管機關規定繳存營業保證金。下列關於營業保 證金之說明，何者錯誤？', '["獨立於經紀業及經紀人員之外，除不動產經紀業管理條例另有規定外，不因其債務債權關係而 為扣押", "得因經紀業或經紀人員之債務債權關係而抵銷", "經紀業合併時，所繳存營業保證金之權利，應隨之移轉", "經紀業申請解散時，得自核准註銷營業之日滿一年後二年內，請求退還原繳存之營業保證金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00653', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '不動產之買賣、互易、租賃或代理銷售，如委由經紀業仲介或代銷者，下列何者不屬不動產經紀 業管理條例規定經紀業應指派經紀人簽章之文件？', '["不動產承租、承購委託契約書", "不動產承租、承購要約書", "定金收據", "不動產廣告稿"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00654', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '不動產經紀業管理條例關於經紀業經營仲介與代銷業務之規範，下列敘述何者正確？', '["受起造人或建築業之委託，負責企劃並代理銷售不動產之業務為仲介業務；從事不動產買賣、 互易、租賃之居間或代理業務為代銷業務", "經營仲介業務者，應將報酬標準及收取方式於營業處所明顯處揭示；經營代銷業務者，則不須 揭示之", "經營仲介業務者，應僱用具備經紀人員資格者從事業務；經營代銷業務者，則無此限制", "經營仲介業務者，有向主管機關申報登錄成交案件實際資訊之義務；經營代銷業務者，則無此義務"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00655', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '有下列何種情形者，不得申請經營經紀業，其經許可者，撤銷或廢止其許可？', '["犯詐欺、背信、侵占罪經受有期徒刑一年以上刑之宣告確定，執行完畢或赦免後已滿三年者", "曾經營經紀業，經主管機關撤銷或廢止許可，自撤銷或廢止之日起已滿五年者", "受停止營業處分，已執行完畢者", "受廢止經紀人員證書或證明處分未滿五年者"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00656', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲通過不動產經紀人考試並領有不動產經紀人證書，從事不動產仲介業務多年，同時擔任乙 仲介公司董事長。執業期間因車禍腦部受創而受法院監護宣告，成為無行為能力人。下列敘 述何者正確？', '["甲得繼續充任不動產經紀人，其資格不受影響", "主管機關應予甲申誡處分", "主管機關應廢止乙公司之營業許可", "由主管機關命乙公司限期改善；逾期未改善者，廢止其許可，並通知公司或商業登記主管機關 廢止其登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00657', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '甲公司接受乙建築公司之委託，簽訂委託契約書後，負責企劃並代理銷售乙公司新推出之公寓大 廈預售屋。下列敘述何者正確？', '["雙方應簽訂委託銷售契約書，並由乙公司指派經紀人於契約書簽章", "甲公司於簽訂委託銷售契約書前，即得刊登廣告並開始銷售", "甲公司應將報酬標準及收取方式揭示於營業處所明顯之處", "乙公司之不動產廣告及銷售內容，應與事實相符，並註明甲公司名稱"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00658', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '公平交易法規定，法院因被害人之請求，如為事業之故意行為，得依侵害情節，酌定損害額以上 之賠償。但不得超過已證明損害額之幾倍？', '["二倍", "三倍", "四倍", "五倍"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00659', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '不動產經紀業者以下何種行為不涉及違法聯合行為？', '["共同決定服務報酬收費標準，或協議限制服務報酬之調整", "協議拒絕其他不動產經紀業者參與聯賣", "共同約束開發物件必須與委託人簽訂一般委託契約", "共同約束專任委託契約之期間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00660', 'real-estate', 'real-estate-moex-108-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列何者非屬內政部所頒不動產說明書不得記載事項之內容？', '["附屬建物除陽台外，其餘項目不得計入買賣價格", "不得記載本說明書內容僅供參考", "不得使用實際所有權面積以外之「受益面積」、「銷售面積」、「使用面積」等類似名詞", "預售屋出售標的，不得記載未經依法領有建造執照之夾層設計或夾層空間面積"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:37+00:00", "source_pdf_sha1": "d66fd5f42297", "answer_pdf_sha1": "a229d5435791", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL);
